INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'jr', 43, 1, NULL, 'Orígenes em Jr 43:1', 'Orígenes interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em Jeremias 43, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Orígenes', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'jr', 44, 1, NULL, 'Richard Baxter em Jr 44:1', 'Richard Baxter destaca a piedade prática e a santificação do coração. Em Jeremias 44, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Richard Baxter', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'jr', 45, 1, NULL, 'Charles Spurgeon em Jr 45:1', 'Charles Spurgeon interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em Jeremias 45, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Charles Spurgeon', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'jr', 46, 1, NULL, 'Jerônimo em Jr 46:1', 'Segundo Jerônimo, a leitura cristológica e eclesial da passagem ilumina o sentido deste texto. Jeremias 46 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Jerônimo', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'jr', 47, 1, NULL, 'John Owen em Jr 47:1', 'Na leitura de John Owen, vemos a piedade prática e a santificação do coração. Jeremias 47 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Owen', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'jr', 48, 1, NULL, 'A. A. Hodge em Jr 48:1', 'Segundo A. A. Hodge, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Jeremias 48 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'A. A. Hodge', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'jr', 49, 1, NULL, 'João Crisóstomo em Jr 49:1', 'João Crisóstomo destaca a leitura cristológica e eclesial da passagem. Em Jeremias 49, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'João Crisóstomo', 'commentary', '#8B4513', NOW()),
